const results = $.steps.searchDocs.response.results || [];
let docsText = '';
results.forEach((r, i) => {
  docsText += '=== DOCUMENT ' + (i+1) + ' ===\n';
  docsText += 'Title: ' + (r.title || 'Untitled') + '\n';
  docsText += 'URL: ' + (r.url || '') + '\n';
  if (r.publishedDate) docsText += 'Published: ' + r.publishedDate + '\n';
  docsText += 'Content:\n' + (r.text || '').slice(0, 2500) + '\n\n';
});
return { docsText, docCount: results.length, sources: results.slice(0, 5).map(r => ({ title: r.title || r.url, url: r.url })) };

const prompt = `You are a knowledgeable research assistant. Answer the user's question based ONLY on the provided document content. If the documents don't contain enough information, say so explicitly.

USER QUESTION: ${$.input.question}

DOCUMENT CONTENT:
${$.steps.compileDocs.output.docsText}

Provide a comprehensive answer that:
1. Directly addresses the question
2. Cites which document(s) the information comes from (by number)
3. Includes relevant quotes or data points
4. Notes any limitations or gaps in the available information

Return ONLY valid JSON:
{
  "answer": "Comprehensive answer to the question",
  "confidence": "high/medium/low",
  "source_references": [
    { "document": 1, "relevance": "What this document contributed to the answer" }
  ],
  "key_quotes": ["Important quotes from the documents"],
  "limitations": "Any gaps or caveats about the answer"
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'unknown', source_references: [], key_quotes: [], limitations: '' }; }

const ai = $.steps.parseAI.output || {};
const sources = $.steps.compileDocs.output.sources || [];
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Document Q&A' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + $.input.question } });
const confEmoji = ai.confidence === 'high' ? ':white_check_mark:' : ai.confidence === 'medium' ? ':warning:' : ':question:';
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Confidence: ' + confEmoji + ' ' + (ai.confidence || 'unknown') + ' | Sources analyzed: ' + $.steps.compileDocs.output.docCount }] });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Answer*\n' + (ai.answer || 'No answer generated.').slice(0, 1900) } });
blocks.push({ type: 'divider' });
if (ai.key_quotes && ai.key_quotes.length > 0) {
  let quotesText = '*Key Quotes*\n';
  ai.key_quotes.slice(0, 3).forEach((q, i) => { quotesText += '> ' + q.slice(0, 400) + '\n\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: quotesText.slice(0, 1900) } });
}
if (ai.source_references && ai.source_references.length > 0) {
  let refText = '*Sources Referenced*\n';
  ai.source_references.forEach(ref => {
    const src = sources[ref.document - 1];
    refText += '- Doc ' + ref.document + (src ? ' (<' + src.url + '|' + src.title + '>)' : '') + ': ' + ref.relevance + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: refText.slice(0, 1900) } });
}
if (ai.limitations) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: '_Limitations: ' + ai.limitations + '_' }] });
}
return { blocks, fallback: 'Q&A: ' + $.input.question };
